    "editorialTrack": "cvbasic-port",
    "sourceText": "' CVBASIC controller test port\nu8 CurrentKey = 255\n\nu8 KeySpriteX = 0\nu8 KeySpriteY = 0\nu8 PanelX = 0\nu8 PanelY = 0\n\ndata HighlightSprites bytes\n  $18,$3C,$7E,$FF,$FF,$7E,$3C,$18\n  $00,$3C,$7E,$FF,$FF,$7E,$3C,$00\n  $FF,$81,$81,$81,$81,$81,$81,$FF\nend data\n\n  text screen\n  sprites 8x8\n  sprites simple\n  copy HighlightSprites to vram.spr_pat\n  clear sprites\n  set sprite count 14\n  print centered at 5, \"CVBASIC PORT\"\n  print centered at 8, \"DUAL CONTROLLERS\"\n  print centered at 9, \"LIVE KEYPAD TEST\"\n  print centered at 14, \"PRESS FIRE\"\n  screen on\n  pause until press\n  wait no fire\n  cls\n  print at 4,1, \"CVBASIC CONTROLLER TEST\"\n  draw_panels\nmain_loop:\n  wait\n\n  if joypad(1).up then\n    set sprite 0 to 39,40,0,9\n  else\n    set sprite 0 to 209,0,0,0\n  end if\n  if joypad(1).left then\n    set sprite 1 to 47,16,0,9\n  else\n    set sprite 1 to 209,0,0,0\n  end if\n  if joypad(1).right then\n    set sprite 2 to 47,64,0,9\n  else\n    set sprite 2 to 209,0,0,0\n  end if\n  if joypad(1).down then\n    set sprite 3 to 55,40,0,9\n  else\n    set sprite 3 to 209,0,0,0\n  end if\n  if joypad(1).button1 then\n    set sprite 4 to 63,24,1,9\n  else\n    set sprite 4 to 209,0,0,0\n  end if\n  if joypad(1).button2 then\n    set sprite 5 to 63,56,1,9\n  else\n    set sprite 5 to 209,0,0,0\n  end if\n  if keypad(1) = 255 then\n    set sprite 6 to 209,0,0,0\n  else\n    CurrentKey = keypad(1)\n    PanelX = 16\n    PanelY = 40\n    place_key_highlight\n    set sprite 6 to KeySpriteY,KeySpriteX,2,9\n  end if\n\n  if joypad(2).up then\n    set sprite 7 to 39,176,0,9\n  else\n    set sprite 7 to 209,0,0,0\n  end if\n  if joypad(2).left then\n    set sprite 8 to 47,152,0,9\n  else\n    set sprite 8 to 209,0,0,0\n  end if\n  if joypad(2).right then\n    set sprite 9 to 47,200,0,9\n  else\n    set sprite 9 to 209,0,0,0\n  end if\n  if joypad(2).down then\n    set sprite 10 to 55,176,0,9\n  else\n    set sprite 10 to 209,0,0,0\n  end if\n  if joypad(2).button1 then\n    set sprite 11 to 63,160,1,9\n  else\n    set sprite 11 to 209,0,0,0\n  end if\n  if joypad(2).button2 then\n    set sprite 12 to 63,192,1,9\n  else\n    set sprite 12 to 209,0,0,0\n  end if\n  if keypad(2) = 255 then\n    set sprite 13 to 209,0,0,0\n  else\n    CurrentKey = keypad(2)\n    PanelX = 152\n    PanelY = 40\n    place_key_highlight\n    set sprite 13 to KeySpriteY,KeySpriteX,2,9\n  end if\n\n  update sprites\n  goto main_loop\n\nsub draw_panels:\n  print at 4,3, \"P1\"\n  print at 21,3, \"P2\"\n  print at 2,5, \"   ^   \"\n  print at 2,6, \"<     >\"\n  print at 2,7, \"   v   \"\n  print at 2,8, \" L   R \"\n  print at 2,9, \" 1 2 3 \"\n  print at 2,10, \" 4 5 6 \"\n  print at 2,11, \" 7 8 9 \"\n  print at 2,12, \" * 0 # \"\n  print at 2,13, \" B   P \"\n  print at 19,5, \"   ^   \"\n  print at 19,6, \"<     >\"\n  print at 19,7, \"   v   \"\n  print at 19,8, \" L   R \"\n  print at 19,9, \" 1 2 3 \"\n  print at 19,10, \" 4 5 6 \"\n  print at 19,11, \" 7 8 9 \"\n  print at 19,12, \" * 0 # \"\n  print at 19,13, \" B   P \"\n  return\n\nsub place_key_highlight:\n  select case CurrentKey\n  case 1\n    KeySpriteX = PanelX + 8\n    KeySpriteY = PanelY + 31\n  case 2\n    KeySpriteX = PanelX + 24\n    KeySpriteY = PanelY + 31\n  case 3\n    KeySpriteX = PanelX + 40\n    KeySpriteY = PanelY + 31\n  case 4\n    KeySpriteX = PanelX + 8\n    KeySpriteY = PanelY + 39\n  case 5\n    KeySpriteX = PanelX + 24\n    KeySpriteY = PanelY + 39\n  case 6\n    KeySpriteX = PanelX + 40\n    KeySpriteY = PanelY + 39\n  case 7\n    KeySpriteX = PanelX + 8\n    KeySpriteY = PanelY + 47\n  case 8\n    KeySpriteX = PanelX + 24\n    KeySpriteY = PanelY + 47\n  case 9\n    KeySpriteX = PanelX + 40\n    KeySpriteY = PanelY + 47\n  case 10\n    KeySpriteX = PanelX + 8\n    KeySpriteY = PanelY + 55\n  case 0\n    KeySpriteX = PanelX + 24\n    KeySpriteY = PanelY + 55\n  case 11\n    KeySpriteX = PanelX + 40\n    KeySpriteY = PanelY + 55\n  case 12\n    KeySpriteX = PanelX + 8\n    KeySpriteY = PanelY + 63\n  case 13\n    KeySpriteX = PanelX + 40\n    KeySpriteY = PanelY + 63\n  case else\n    KeySpriteX = 0\n    KeySpriteY = 209\n  end select\n  return"
